import{c as a,Q as r,j as t,m as i}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"RouteLLM: Learning to Route LLMs with Preference Data","description":"","frontmatter":{"title":"RouteLLM: Learning to Route LLMs with Preference Data","arxiv_id":2406.18665,"authors":"Isaac Sim, Shuwen Sun, and others","published":"2024-06-20T00:00:00.000Z","source":"https://arxiv.org/abs/2406.18665","venue":"arXiv"},"headers":[],"relativePath":"research/papers/2024-06-20-routellm-learning-to-route-llms-2406.18665.md","filePath":"research/papers/2024-06-20-routellm-learning-to-route-llms-2406.18665.md","lastUpdated":1779901665000}'),o={name:"research/papers/2024-06-20-routellm-learning-to-route-llms-2406.18665.md"};function n(s,e,l,h,d,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="routellm-learning-to-route-llms-with-preference-data" tabindex="-1">RouteLLM: Learning to Route LLMs with Preference Data <a class="header-anchor" href="#routellm-learning-to-route-llms-with-preference-data" aria-label="Permalink to &quot;RouteLLM: Learning to Route LLMs with Preference Data&quot;">​</a></h1><p><strong>Authors</strong>: Isaac Sim, Shuwen Sun, and others</p><p><strong>Published</strong>: June 20, 2024</p><p><strong>Source</strong>: <a href="https://arxiv.org/abs/2406.18665" target="_blank" rel="noreferrer">https://arxiv.org/abs/2406.18665</a></p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>This research paper introduces RouteLLM, a framework for training router models that dynamically select between strong (expensive, high-quality) and weak (cheap, lower-quality) LLMs during inference. The key innovation is leveraging human preference data to achieve significant cost savings while maintaining response quality.</p><hr><h2 id="core-problem-solution" tabindex="-1">Core Problem &amp; Solution <a class="header-anchor" href="#core-problem-solution" aria-label="Permalink to &quot;Core Problem &amp; Solution&quot;">​</a></h2><p>The paper addresses a fundamental challenge in LLM deployment: balancing performance against cost. Rather than routing all queries to expensive models or sacrificing quality with cheap ones, RouteLLM learns which queries genuinely need the stronger model.</p><p>The framework uses two components:</p><ol><li><strong>Win Prediction Model</strong>: Estimates probability that a strong model outperforms a weak model for a given query</li><li><strong>Cost Threshold (α)</strong>: A parameter controlling the quality-cost tradeoff by determining routing decisions</li></ol><hr><h2 id="key-contributions" tabindex="-1">Key Contributions <a class="header-anchor" href="#key-contributions" aria-label="Permalink to &quot;Key Contributions&quot;">​</a></h2><h3 id="data-training-approaches" tabindex="-1">Data &amp; Training Approaches <a class="header-anchor" href="#data-training-approaches" aria-label="Permalink to &quot;Data &amp; Training Approaches&quot;">​</a></h3><p>The researchers built training datasets from:</p><ul><li>80K human preferences from Chatbot Arena</li><li>Golden-labeled datasets (MMLU validation split)</li><li>GPT-4 judge-labeled datasets (~120K samples)</li></ul><p>They evaluated four router architectures: similarity-weighted ranking, matrix factorization, BERT classifier, and causal LLM classifier.</p><h3 id="performance-results" tabindex="-1">Performance Results <a class="header-anchor" href="#performance-results" aria-label="Permalink to &quot;Performance Results&quot;">​</a></h3><p>The routers achieved remarkable efficiency gains. As stated in their findings: &quot;routers achieve cost savings of up to 3.66x&quot; while maintaining quality comparable to using only expensive models.</p><p>On MT Bench specifically, their best routers reduced GPT-4 calls by ~75% while recovering 95% of GPT-4&#39;s performance.</p><hr><h2 id="notable-findings" tabindex="-1">Notable Findings <a class="header-anchor" href="#notable-findings" aria-label="Permalink to &quot;Notable Findings&quot;">​</a></h2><ol><li><p><strong>Data Augmentation Matters</strong>: Routers trained only on arena data performed poorly on specialized benchmarks (MMLU, GSM8K), but augmentation with domain-specific data dramatically improved performance.</p></li><li><p><strong>Generalization Across Models</strong>: A single trained router maintained strong performance when routing between different model pairs (Claude 3, Llama 3.1) without retraining—crucial for real-world deployment.</p></li><li><p><strong>Benchmark-Dataset Similarity</strong>: They introduced a quantitative similarity metric showing &quot;strong correlation between similarity scores and router performance,&quot; helping explain performance variations across benchmarks.</p></li><li><p><strong>Minimal Overhead</strong>: Routing adds less than 0.4% cost overhead compared to GPT-4 generation.</p></li></ol><hr><h2 id="methodology-highlights" tabindex="-1">Methodology Highlights <a class="header-anchor" href="#methodology-highlights" aria-label="Permalink to &quot;Methodology Highlights&quot;">​</a></h2><p>The similarity-weighted ranking approach adapted Bradley-Terry models from ranking theory, while matrix factorization techniques treated routing as a recommendation system problem. This diversity of approaches showed that simpler, parameter-efficient methods sometimes outperformed larger neural classifiers in low-data regimes.</p><hr><h2 id="limitations-future-work" tabindex="-1">Limitations &amp; Future Work <a class="header-anchor" href="#limitations-future-work" aria-label="Permalink to &quot;Limitations &amp; Future Work&quot;">​</a></h2><p>The authors acknowledge this work focuses on binary routing. Extending to N-way routing among multiple models remains an open challenge, as does understanding real-world query distributions that may differ from academic benchmarks.</p>',30)])])}const p=a(o,[["render",n]]);export{m as __pageData,p as default};
